#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int N, M; cin >> N >> M;
    vector<vector<int>> adj(N + 1);
    for (int i = 0; i < M; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    int S, E; cin >> S >> E;
    vector<bool> vis(N + 1, false);
    queue<int> q;
    q.push(S); vis[S] = true;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        for (int nx : adj[cur]) {
            if (!vis[nx]) { vis[nx] = true; q.push(nx); }
        }
    }
    cout << (vis[E] ? "YES" : "NO") << "\n";
    return 0;
}
